import{_ as e,o,c as a,ag as i}from"./chunks/framework-C5-Jzrz4.js";const d=JSON.parse('{"title":"项目概述","description":"Lxy-Vue-Admin 的定位、技术栈和结构概览","frontmatter":{"title":"项目概述","description":"Lxy-Vue-Admin 的定位、技术栈和结构概览"},"headers":[],"relativePath":"scripts/guide/01-项目概述.md","filePath":"scripts/guide/01-项目概述.md","lastUpdated":null}');const c=e({name:"scripts/guide/01-项目概述.md"},[["render",function(e,d,c,l,t,r){return o(),a("div",null,[...d[0]||(d[0]=[i('<h1 id="项目概述" tabindex="-1">项目概述 <a class="header-anchor" href="#项目概述" aria-label="Permalink to &quot;项目概述&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p><code>Lxy-Vue-Admin</code> 是基于 <code>Vben Admin 5.7.0</code>、<code>Vue 3.5</code>、<code>Vite 8</code> 和 <code>antdv-next</code> 的企业后台前端项目，采用 <code>pnpm workspace + Turbo</code> 的 Monorepo 结构。</p><h2 id="适用范围" tabindex="-1">适用范围 <a class="header-anchor" href="#适用范围" aria-label="Permalink to &quot;适用范围&quot;">​</a></h2><ul><li>了解项目边界和主要技术选型</li><li>快速定位主应用、共享包和内部工具目录</li></ul><h2 id="对应源码目录或关键文件" tabindex="-1">对应源码目录或关键文件 <a class="header-anchor" href="#对应源码目录或关键文件" aria-label="Permalink to &quot;对应源码目录或关键文件&quot;">​</a></h2><ul><li>根配置：<code>package.json</code>、<code>pnpm-workspace.yaml</code>、<code>turbo.json</code></li><li>主应用：<code>apps/web-antd</code></li><li>共享包：<code>packages/*</code></li><li>内部工具：<code>internal/*</code></li></ul><h2 id="核心机制或功能说明" tabindex="-1">核心机制或功能说明 <a class="header-anchor" href="#核心机制或功能说明" aria-label="Permalink to &quot;核心机制或功能说明&quot;">​</a></h2><h3 id="技术栈-以当前源码依赖为准" tabindex="-1">技术栈（以当前源码依赖为准） <a class="header-anchor" href="#技术栈-以当前源码依赖为准" aria-label="Permalink to &quot;技术栈（以当前源码依赖为准）&quot;">​</a></h3><ul><li>核心：<code>vue@^3.5.30</code>、<code>vite@^8.0.1</code>、<code>typescript@^5.9.3</code></li><li>路由与状态：<code>vue-router@^5.0.4</code>、<code>pinia@^3.0.4</code></li><li>UI：<code>antdv-next@^1.1.7</code></li><li>请求：<code>alova@^3.4.1</code> + <code>axios@^1.13.6</code></li><li>工程：<code>pnpm@10.32.1</code>、<code>turbo@^2.8.20</code></li></ul><h3 id="monorepo-主体目录" tabindex="-1">Monorepo 主体目录 <a class="header-anchor" href="#monorepo-主体目录" aria-label="Permalink to &quot;Monorepo 主体目录&quot;">​</a></h3><ul><li><code>apps/web-antd</code>：业务应用集成层</li><li><code>packages/@core/*</code>：基础与 UI 套件核心能力</li><li><code>packages/effects/*</code>：组合能力（布局、通用 UI、请求、插件、权限）</li><li><code>packages/{constants,icons,locales,preferences,stores,styles,types,utils}</code>：通用基础包</li><li><code>internal/*</code>：lint、tsconfig、vite-config、tailwind-config 等内部工具</li><li><code>docs</code>：VitePress 站点</li></ul><h2 id="使用方式、扩展方式或注意事项" tabindex="-1">使用方式、扩展方式或注意事项 <a class="header-anchor" href="#使用方式、扩展方式或注意事项" aria-label="Permalink to &quot;使用方式、扩展方式或注意事项&quot;">​</a></h2><ul><li>新业务页面优先落在 <code>apps/web-antd/src/views</code>。</li><li>共享能力优先复用 <code>packages</code> 现有模块，避免在应用层重复封装。</li><li>文档阅读建议先看 <a href="./03-架构设计说明">架构设计说明</a> 与 <a href="./04-核心模块功能详解">核心模块功能详解</a>。</li><li>API 说明入口在 <a href="./../api/README">API 文档</a>。</li></ul>',14)])])}]]);export{d as __pageData,c as default};
